const row = $input.first().json || {};
const demandFloor = Number(row.demand_floor ?? 0);
const shouldDispatch = row.system_mode === 'NORMAL' && Number(row.risk_score || 0) < 30 && row.direction === 'IDLE' && row.door_state !== 'BLOCKED' && Number(row.current_floor) !== demandFloor && Number(row.samples || 0) >= 3;
const thingId = row.thing_id || $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const correlationId = `CID-OPT-DISPATCH-${thingId.replace(/[^a-zA-Z0-9]/g, '-')}-${Date.now()}`;
const issuedAt = new Date().toISOString();
return [{ json: { thing_id: thingId, correlation_id: correlationId, agent_source: '06_optimization_audit_agents', should_dispatch: shouldDispatch, triggered_action: { agent: 'control', command: 'REPOSITION', priority: 'LOW', target_floor: demandFloor, reason: [`PREDICTIVE_DISPATCH_H${new Date().getHours()}`], source_agent: '06_optimization_audit_agents', correlation_id: correlationId, risk_score: Number(row.risk_score || 0), issued_at: issuedAt }, dispatch_analysis: { demand_floor: demandFloor, samples: Number(row.samples || 0), current_floor: Number(row.current_floor), risk_score: Number(row.risk_score || 0) } } }];

const thing = $input.first().json || {};
const cabin = thing.features?.cabin?.properties || {};
const motor = thing.features?.motor?.properties || {};
return [{ json: { thing_id: thing.thingId || 'building:floor1:elevator', load_kg: cabin.load_kg ?? 0, direction: cabin.direction ?? 'IDLE', current_floor: cabin.current_floor ?? 0, power_kw: motor.power_kw ?? 0, current_draw_a: motor.current_draw_a ?? 0, vibration_g: motor.vibration_g ?? motor.vibration_level ?? 0, system_mode: thing.attributes?.system_mode || 'NORMAL' } }];

const row = $input.first().json || {};
const num = (value, fallback = 0) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
};

const thingId = row.thing_id || $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const currentFloor = num(row.current_floor);
const baselinePower = num(row.baseline_power_kw);
const baselineCurrent = num(row.baseline_current_a);
const baselineVibration = num(row.baseline_vibration_g);
const currentPower = num(row.current_power_kw ?? row.power_kw);
const currentCurrent = num(row.current_draw_a);
const currentVibration = num(row.current_vibration_g ?? row.vibration_g);
const loadKg = num(row.load_kg);
const demandFloor = Number.isFinite(Number(row.predicted_demand_floor)) ? Number(row.predicted_demand_floor) : currentFloor;

const recommendations = [];
if (baselinePower > 0 && currentPower > baselinePower * 1.25) recommendations.push('POWER_SPIKE');
if (baselineCurrent > 0 && currentCurrent > baselineCurrent * 1.25) recommendations.push('CURRENT_DRAW_ELEVATED');
if (baselineVibration > 0 && currentVibration > baselineVibration * 1.5) recommendations.push('VIBRATION_ELEVATED');
if (loadKg < 50 && baselinePower > 0 && currentPower > baselinePower * 1.2) recommendations.push('HIGH_CONSUMPTION_LOW_LOAD');

let energyMode = 'NORMAL';
if (recommendations.includes('HIGH_CONSUMPTION_LOW_LOAD') || row.direction === 'IDLE') energyMode = 'SAVING';
if (Number(row.samples || 0) >= 10 && loadKg > 200) energyMode = 'PEAK';

const maintenanceLinked = recommendations.some((item) => ['VIBRATION_ELEVATED', 'CURRENT_DRAW_ELEVATED'].includes(item));
const confidence = Math.min(1, Math.max(0.2, Number(row.samples || 0) / 20));

return [{
  json: {
    ...row,
    thing_id: thingId,
    should_notify: recommendations.length > 0,
    should_open_maintenance_review: maintenanceLinked,
    optimization: {
      recommended_parking_floor: demandFloor,
      predicted_demand_floor: demandFloor,
      energy_mode: energyMode,
      confidence: Math.round(confidence * 100) / 100,
      recommendations,
      updated_at: new Date().toISOString()
    },
    risk_analysis: {
      severity: recommendations.length > 0 ? 'WARNING' : 'OK',
      risk_score: recommendations.length > 0 ? 45 : 0,
      flags: recommendations
    }
  }
}];

const rows = $input.all().map((item) => item.json);
const html = rows.map((row) => `<h3>${row.thing_id}</h3><ul><li>Total events: ${row.total_events}</li><li>Peak risk: ${row.peak_risk}</li><li>Average risk: ${row.avg_risk}</li><li>Security breaches: ${row.security_breaches}</li><li>Life safety events: ${row.life_safety_events}</li><li>Average power: ${row.avg_power_kw} kW</li><li>P95 vibration: ${row.p95_vibration_g} g</li><li>Period: ${row.period_start} to ${row.period_end}</li></ul>`).join('');
return [{ json: { html, subject: 'Weekly ElevatorOS Compliance Report' } }];
